def _priority_popen_kwargs(self) -> dict[str, t.Any]:
    """Build extra keyword arguments for ``subprocess.Popen`` that
    apply ``self.process_priority`` to the spawned editor process,
    using the appropriate mechanism for the current platform.
    """
    if self.process_priority is None:
        return {}

    if WIN:
        try:
            import subprocess

            priority_classes = {
                "low": subprocess.IDLE_PRIORITY_CLASS,
                "below_normal": subprocess.BELOW_NORMAL_PRIORITY_CLASS,
                "normal": subprocess.NORMAL_PRIORITY_CLASS,
                "above_normal": subprocess.ABOVE_NORMAL_PRIORITY_CLASS,
                "high": subprocess.HIGH_PRIORITY_CLASS,
            }
            return {"creationflags": priority_classes[self.process_priority]}
        except Exception:
            return {}
    else:
        try:
            niceness = {
                "low": 10,
                "below_normal": 5,
                "normal": 0,
                "above_normal": -5,
                "high": -10,
            }[self.process_priority]

            def _set_priority() -> None:
                try:
                    os.nice(niceness)
                except OSError:
                    pass

            return {"preexec_fn": _set_priority}
        except Exception:
            return {}

